/// `- 1` discounts the sentinel `{NULL, NULL}` entry; the Rust slice has
/// no sentinel, so we use `funcs.len()` directly.
pub fn new_lib_table(
    &mut self,
    funcs: &[(&[u8], LuaCFunction)],
) -> Result<(), LuaError> {
    create_table(self, 0, funcs.len() as i32)
