/// `-(nup + 2)`, sharing the `nup` values currently on top of the stack
/// as upvalues. The upvalues are popped at the end.
///
/// C: `luaL_setfuncs(L, l, nup)`.
pub fn set_funcs_with_upvalues(
    &mut self,
    funcs: &[(&[u8], LuaCFunction)],
    nup: i32,
) -> Result<(), LuaError> {
    check_stack(self, nup);
    for (name, f) in funcs {
